output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?game ?duration WHERE {
  ?competition rdfs:label ?name .
  FILTER(LANG(?name) = 'en')
  .
  FILTER(CONTAINS(LCASE(?name) , 'national league championship series'))
  ?competition wdt:P585 ?compDate .
  FILTER(YEAR(?compDate) IN(1977 , 1978 , 2008 , 2009))
  ?game wdt:P1542 ?competition .
  {
    ?game wdt:P1322 wd:Q3137019 ; wdt:P1323 wd:Q347351
  } UNION {
    ?game wdt:P1322 wd:Q347351 ; wdt:P1323 wd:Q3137019
  }
  ?game wdt:P2543 ?duration .
}
ORDER BY DESC(?duration)
LIMIT 16

